}

{
  "jurisdiction": "PH",
  "section_id": "203",
  "title": ". Prohibition. No agent, attorney or other person pursuing or in charge of the preparation or filing",
  "content": ". Prohibition. No agent, attorney or other person pursuing or in charge of the preparation or filing of \nany claim for benefit under this Title shall demand or charge for his services any fee, and any stipulation to the \ncontrary shall be null and void. The retention or deduction of any amount from any benefit granted under this \nTitle for the payment of fees for such services is prohibited. Violation of any provision of this Article shall be \npunished by a fine of not less than five hundred pesos nor more than five thousand pesos, or imprisonment for \nnot less than six months nor more than one year, or both, at the discretion of the court.",
  "is_repealed": false,
  "metadata": {
    "source_file": "Labor-Code-of-the-Philippines-DOLE.pdf",
    "jurisdiction": "PH",
    "corpus_category": "wages",
    "timestamp": "2026-01-21T14:28:38.518074"
  }
}

{
  "jurisdiction": "PH",
  "section_id": "96",
  "title": ". Service charges. All service charges collected by hotels, restaurants and similar establishments s",
  "content": ". Service charges. All service charges collected by hotels, restaurants and similar establishments shall \nbe distributed at the rate of eighty-five percent (85%) for all covered employees and fifteen percent (15%) for \nmanagement. The share of the employees shall be equally distributed among them. In case the service \ncharge is abolished, the share of the covered employees shall be considered integrated in their wages. \nTitle II \nWAGES \nChapter I \nPRELIMINARY MATTERS",
  "is_repealed": false,
  "metadata": {
    "source_file": "Labor-Code-of-the-Philippines-DOLE.pdf",
