  }
}

{
  "jurisdiction": "PH",
  "section_id": "216",
  "title": ". Salaries, benefits and other emoluments. The Chairman and members of the Commission shall ",
  "content": ". Salaries, benefits and other emoluments. The Chairman and members of the Commission shall \nreceive an annual salary at least equivalent to, and be entitled to the same allowances and benefits as those \nof the Presiding Justice and Associate Justices of the Court of Appeals, respectively. The Executive Labor \nArbiters shall receive an annual salary at least equivalent to that of an Assistant Regional Director of the \nDepartment of Labor and Employment and shall be entitled to the same allowances and benefits as that of a \nRegional Director of said Department. The Labor Arbiters shall receive an annual salary at least equivalent to, \nand be entitled to the same allowances and benefits as that of an Assistant Regional Director of the \nDepartment of Labor and Employment. In no case, however, shall the provision of this Article result in the \ndiminution of existing salaries, allowances and benefits of the aforementioned officials. (As amended by \nSection 8, Republic Act No. 6715, March 21, 1989) \nChapter II \nPOWERS AND DUTIES",
  "is_repealed": false,
  "metadata": {
    "source_file": "Labor-Code-of-the-Philippines-DOLE.pdf",
    "jurisdiction": "PH",
